INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00141', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員以繼續營業單位之稅前淨利某一百分比作為計算財務報表整體重大性之起點，下列 敘述何者不適當？', '["查核人員受託查核某年度上半年度財務報表查核，於決定重大性時，應以上半年度之財務 報表推算為 12 個月的繼續營業單位稅前淨利計算重大性，以與年度財務報表查核時採用 12個月的財務資訊計算重大性一致", "查核人員於查核過程中發現實際財務績效與原用以決定財務報表整體重大性之預期財務績 效存有重大差異，應修正該重大性", "受查者當年度繼續營業單位之稅前淨利較以往年度大幅減少，趨近於損益兩平，查核人員 可以採用過去3年之平均數計算重大性", "受查者當年度繼續營業單位之稅前淨利$1,000,000，其中包括火災損失$500,000，查核人員 考量火災損失是當年度之異常項目，為常態化繼續營業單位之稅前淨利以$1,500,000 計算 重大性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00142', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員因應管理階層踰越控制所導致舞弊之重大不實表達風險，下列那一項通常不屬於查 核人員應設計並執行之查核程序？', '["測試普通日記簿分錄及編製財務報表所作其他調整之適當性", "向受查者主管機關查詢，以確認其是否知悉已發生、疑似或傳聞之舞弊", "複核可能導致重大不實表達之會計估計", "瞭解不尋常或非正常營運之重大交易，其交易動機及合理性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00143', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關重大不實表達風險之因應，下列敘述何者正確？', '["查核人員已於期中取得有關控制執行有效性之查核證據，若該等控制於該期間後未發生改 變，查核人員對期中查核後剩餘期間受查者所執行之控制，無須取得額外之查核證據", "查核人員對經其判斷為顯著風險之相關控制，如計劃予以信賴時，應於當期測試該等控制", "查核人員如計劃採用以往查核所取得對特定控制執行有效之查核證據時，應取得該等控制 於以往查核後未發生改變影響查核證據持續攸關性之證據，如未發生改變，查核人員仍應 至少每2年測試該等控制一次", "對財務報表某一個別項目聲明執行證實程序時未偵出不實表達，可作為與該聲明相關之控 制係有效執行之查核證據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00144', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者為財務報表查核中管理階層應負之責任？① 維持與財務報表編製有關之必要內部控', '["評估企業繼續經營能力與採用繼續經營會計基礎是否適當", "使查核人員得以接觸管 理階層所知悉與財務報表編製攸關之所有資訊", "使查核人員得以基於查核目的而向管理階 層要求額外資訊", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00145', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於執行風險評估之查核程序時，下列何者之順序較為適當？①評估固有風險及控制', '["訂定可接受之查核風險", "訂定可接受之偵查風險", "決定查核之時間、性質及 範圍", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00146', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核財務報表時對法令遵循之查核，下列那一項查核人員的做法是錯誤的？', '["對財務報表之重大金額及揭露具直接影響之法令，查核人員應就該等法令之遵循取得足夠 及適切之查核證據", "對財務報表之金額及揭露不具直接影響之其他法令，查核人員對此類法令之遵循應取得足 夠及適切之查核證據", "會計師如辨認出未遵循或疑似未遵循法令事項，應確定法令或相關職業道德規範是否規定 須向適當之權責機關報告", "查核人員應要求管理階層（如適當時，亦包括治理單位），就其已告知查核人員編製財務報 表時須考量之所有已知未遵循或疑似未遵循法令事項，提供書面聲明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00147', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於決定是否採用查核人員專家之工作，以協助其對特定事項取得足夠及適切之查核 證據時，以下何者並非所考量之因素？', '["可否於查核報告中提及查核人員專家之工作", "該事項之性質及重要性，包括其複雜程度", "該事項之重大不實表達風險", "可否取得替代查核證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00148', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關期後事項之查核，下列敘述何者錯誤？', '["查核人員於查核報告日後，並無對財務報表執行任何查核程序之義務", "會計師查核報告日不得晚於財務報表核准日", "查核人員應閱讀財務報表結束日後至查核報告日之期間所召開之董事會議事錄，若該等紀 錄尚未完成，則應查詢會議中討論之事項", "查核人員於財務報表發布後獲悉某事實，而該事實若於查核報告日即獲悉，可能導致會計 師修改查核報告時，查核人員應就該事項與管理階層討論，及決定財務報表是否須作修改"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00149', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '為測試控制而使用統計抽樣時，下列敘述何者正確？', '["其他因素不變的情形下，會計師若將過度信賴風險訂得越高，則所需的樣本量越小", "變量抽樣法適合測試控制時使用", "選樣時可採用隨意選樣（haphazardsampleselection）法", "所需之樣本量與母體量呈正比"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00150', 'cpa', 'cpa-moex-113-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於參與受查者存貨盤點時所執行之查核程序，下列敘述何者錯誤？', '["查核人員通常會檢查存貨以確認其存在並評估存貨狀況", "自盤點紀錄選取項目追查到實體存貨，作為存貨紀錄完整性之驗證程序", "觀察管理階層指示之遵循情形及記錄與控制存貨盤點結果程序之執行情形", "取得管理階層盤點程序可靠性之查核證據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "c454e2e4181e", "answer_pdf_sha1": "682d8bf1106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
